SELECT * FROM t_optimization_ticket
WHERE tenant_id = #{tenantId}
ORDER BY created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT * FROM t_optimization_ticket
WHERE tenant_id = #{tenantId} AND assignee = #{assignee}
